// UserService.java
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;

import java.util.List;
import java.util.Random;
import java.util.stream.Collectors;
import java.util.stream.IntStream;

@Service
public class UserService {
    @Autowired
    private UserRepository userRepository;

    @Autowired
    private BackupCodeRepository backupCodeRepository;

    public List<String> generateBackupCodes(User user) {
        List<BackupCode> codes = IntStream.range(0, 10)
                .mapToObj(i -> {
                    BackupCode code = new BackupCode();
                    code.setCode(generateRandomCode());
                    code.setUser(user);
                    code.setUsed(false);
                    return code;
                }).collect(Collectors.toList());

        backupCodeRepository.saveAll(codes);
        return codes.stream().map(BackupCode::getCode).collect(Collectors.toList());
    }

    private String generateRandomCode() {
        return new Random().ints(48, 122)
                .filter(i -> (i <= 57 || i >= 65) && (i <= 90 || i >= 97))
                .limit(8)
                .collect(StringBuilder::new, StringBuilder::appendCodePoint, StringBuilder::append)
                .toString();
    }

    public boolean authenticateWithBackupCode(String username, String code) {
        User user = userRepository.findByUsername(username);
        if (user != null) {
            BackupCode backupCode = backupCodeRepository.findByCodeAndUser(code, user);
            if (backupCode != null && !backupCode.isUsed()) {
                backupCode.setUsed(true);
                backupCodeRepository.save(backupCode);
                return true;
            }
        }
        return false;
    }
}

// UserController.java
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.web.bind.annotation.*;

import java.util.List;

@RestController
@RequestMapping("/api/users")
public class UserController {
    @Autowired
    private UserService userService;

    @PostMapping("/{username}/enable-mfa")
    public List<String> enableMfa(@PathVariable String username) {
        User user = userService.findByUsername(username);
        if (user != null) {
            user.setMfaEnabled(true);
            userService.save(user);
            return userService.generateBackupCodes(user);
        }
        return null;
    }

    @PostMapping("/{username}/authenticate")
    public boolean authenticate(@PathVariable String username, @RequestParam String code) {
        return userService.authenticateWithBackupCode(username, code);
    }
}